import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterLink } from '@angular/router';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { CartService } from '../../core/services/cart.service';
import { OrdersService } from '../../core/services/orders.service';
import { AuthService } from '../../core/services/auth.service';
import { MoneyPipe } from '../../shared/money.pipe';

@Component({
  selector: 'app-checkout',
  standalone: true,
  imports: [CommonModule, RouterLink, ReactiveFormsModule, MoneyPipe],
  templateUrl: './checkout.component.html',
  styleUrls: ['./checkout.component.css'],
})
export class CheckoutComponent {
  private fb = inject(FormBuilder);
  private router = inject(Router);
  cart = inject(CartService);
  private orders = inject(OrdersService);
  private auth = inject(AuthService);

  submitting = signal(false);
  errorMessage = signal('');

  form = this.fb.nonNullable.group({
    shipName: [this.auth.user()?.name ?? '', [Validators.required]],
    shipAddress: ['', [Validators.required, Validators.minLength(6)]],
  });

  readonly outOfStock = computed(() => this.cart.items().some((i) => i.quantity > i.stockQty));

  placeOrder(): void {
    if (this.form.invalid || this.cart.items().length === 0) {
      this.form.markAllAsTouched();
      return;
    }
    if (this.outOfStock()) {
      this.errorMessage.set('Some items exceed available stock. Please adjust your cart.');
      return;
    }
    this.submitting.set(true);
    const { shipName, shipAddress } = this.form.getRawValue();
    const order = this.orders.placeOrder(
      this.cart.items(),
      shipName,
      shipAddress,
      this.auth.user()?.email ?? 'guest@demo',
    );
    this.cart.clear();
    this.router.navigate(['/orders', order.id]);
  }
}
